import React, { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { addStudent } from '../store/slices/admissionSlice';
import toast from 'react-hot-toast';

const FEE_BADGE = {
  paid:    ['#D1FAE5','#065F46','✓ Paid'],
  pending: ['#FEE2E2','#991B1B','Pending'],
  partial: ['#FEF3C7','#92400E','Partial'],
};

const EMPTY = {
  firstName:'', lastName:'', dob:'', gender:'male', blood:'', category:'general',
  aadhaar:'', religion:'', class_:'', section:'A',
  admDate: new Date().toISOString().split('T')[0],
  prevSchool:'', prevMarks:'',
  fatherName:'', motherName:'', phone:'', altPhone:'', email:'',
  city:'', state:'Uttar Pradesh', pincode:'', address:'',
};

const inp = (extra={}) => ({ width:'100%', padding:'10px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', fontFamily:'inherit', background:'#fff', boxSizing:'border-box', ...extra });
const Field = ({label,required,err,children}) => (
  <div style={{display:'flex',flexDirection:'column',gap:5}}>
    <label style={{fontSize:11,fontWeight:700,color:'#4B5563',textTransform:'uppercase',letterSpacing:'.06em'}}>
      {label}{required&&<span style={{color:'#DC2626',marginLeft:3}}>*</span>}
    </label>
    {children}
    {err&&<span style={{color:'#DC2626',fontSize:11}}>{err}</span>}
  </div>
);
const Sec = ({title}) => <div style={{fontSize:11,fontWeight:800,color:'#1E1B4B',textTransform:'uppercase',letterSpacing:'.08em',margin:'20px 0 12px',paddingBottom:8,borderBottom:'2px solid #EDE9F8'}}>{title}</div>;

export default function Students() {
  const dispatch   = useDispatch();
  const students   = useSelector(s => s.admission.students);
  const classes    = useSelector(s => s.admission.classes);

  const [search,     setSearch]    = useState('');
  const [filterCls,  setFilterCls] = useState('');
  const [filterFee,  setFilterFee] = useState('');
  const [showAdd,    setShowAdd]   = useState(false);
  const [viewSt,     setViewSt]    = useState(null);
  const [step,       setStep]      = useState(1);
  const [form,       setForm]      = useState(EMPTY);
  const [errors,     setErrors]    = useState({});

  const f = (k,v) => setForm(p=>({...p,[k]:v}));

  const filtered = students.filter(s => {
    const q = search.toLowerCase();
    return (
      (!q || s.name.toLowerCase().includes(q) || s.adm.includes(q) || s.phone.includes(q)) &&
      (!filterCls || s.cls === filterCls) &&
      (!filterFee || s.fee === filterFee)
    );
  });

  const validate = () => {
    const e = {};
    if (step===1) { if (!form.firstName.trim()) e.firstName='Required'; if (!form.dob) e.dob='Required'; }
    if (step===2) {
      if (!form.fatherName.trim()) e.fatherName='Required';
      if (!form.phone.trim())      e.phone='Required';
      if (form.phone && !/^\d{10}$/.test(form.phone)) e.phone='Must be 10 digits';
    }
    if (step===3) { if (!form.class_.trim()) e.class_='Select a class'; }
    setErrors(e);
    return !Object.keys(e).length;
  };

  const openAdd = () => { setForm(EMPTY); setErrors({}); setStep(1); setShowAdd(true); setViewSt(null); };
  const closeAdd = () => { setShowAdd(false); setErrors({}); setStep(1); };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!validate()) return;
    if (step < 3) { setStep(step+1); return; }
    dispatch(addStudent({
      name:   `${form.firstName} ${form.lastName}`.trim(),
      cls:    form.class_, sec: form.section,
      parent: form.fatherName, phone: form.phone,
      cat:    form.category, dob: form.dob,
      gender: form.gender, blood: form.blood,
      addr:   `${form.address}, ${form.city}`.replace(/^, /,''),
    }));
    toast.success(`✅ ${form.firstName} ${form.lastName} admitted successfully!`);
    closeAdd();
  };

  const STEPS = ['Student Info','Parent Info','Academic'];

  return (
    <div style={{position:'relative'}}>
      {/* Header */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Students</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>{filtered.length} of {students.length} students enrolled</p>
        </div>
        <div style={{display:'flex',gap:10}}>
          <button style={{padding:'9px 14px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:12,fontWeight:600,color:'#374151',cursor:'pointer'}}>📥 Export Excel</button>
          <button onClick={openAdd} style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ New Admission</button>
        </div>
      </div>

      {/* Filters */}
      <div style={{display:'flex',gap:10,marginBottom:16,flexWrap:'wrap'}}>
        <input placeholder="🔍 Search by name, admission no, phone…" value={search} onChange={e=>setSearch(e.target.value)} style={{...inp(),maxWidth:320,flex:1}}/>
        <select value={filterCls} onChange={e=>setFilterCls(e.target.value)} style={{...inp(),width:'auto'}}>
          <option value=''>All Classes</option>{classes.map(c=><option key={c}>{c}</option>)}
        </select>
        <select value={filterFee} onChange={e=>setFilterFee(e.target.value)} style={{...inp(),width:'auto'}}>
          <option value=''>Fee: All</option><option value='paid'>Paid</option><option value='pending'>Pending</option><option value='partial'>Partial</option>
        </select>
        {(search||filterCls||filterFee)&&<button onClick={()=>{setSearch('');setFilterCls('');setFilterFee('');}} style={{padding:'9px 14px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:12,color:'#6B7280',cursor:'pointer'}}>Clear ✕</button>}
      </div>

      {/* Table */}
      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
          <thead><tr style={{background:'#F9FAFB'}}>
            {['Adm No.','Student','Class','Parent / Phone','Category','Fee','Status','Actions'].map(h=>(
              <th key={h} style={{padding:'10px 14px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:700,textTransform:'uppercase',borderBottom:'1px solid #E5E7EB',whiteSpace:'nowrap'}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>
            {filtered.length===0&&<tr><td colSpan={8} style={{padding:48,textAlign:'center',color:'#9CA3AF'}}><div style={{fontSize:36,marginBottom:10}}>👨‍🎓</div><div style={{fontWeight:600,fontSize:14,color:'#6B7280'}}>No students found</div><div style={{fontSize:12,marginTop:4}}>Click "+ New Admission" to add a student</div></td></tr>}
            {filtered.map(s=>{
              const [bg,c,label]=FEE_BADGE[s.fee]||FEE_BADGE.pending;
              return (
                <tr key={s.id} style={{borderBottom:'0.5px solid #F3F4F6',transition:'background .1s',cursor:'pointer'}}
                  onMouseEnter={e=>e.currentTarget.style.background='#F5F3FF'}
                  onMouseLeave={e=>e.currentTarget.style.background=''}>
                  <td style={{padding:'11px 14px',fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{s.adm}</td>
                  <td style={{padding:'11px 14px'}}>
                    <div style={{display:'flex',alignItems:'center',gap:9}}>
                      <div style={{width:32,height:32,borderRadius:8,background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:14,fontWeight:700,color:'#1E1B4B',flexShrink:0}}>{s.name[0]}</div>
                      <div>
                        <div style={{fontWeight:700,color:'#111827'}}>{s.name}</div>
                        {s.fromRegistration&&<div style={{fontSize:10,color:'#7C3AED'}}>📄 From reg {s.regNo}</div>}
                        {s.dob&&<div style={{fontSize:10,color:'#9CA3AF'}}>DOB: {s.dob}</div>}
                      </div>
                    </div>
                  </td>
                  <td style={{padding:'11px 14px',fontWeight:500,color:'#374151'}}>{s.cls} — {s.sec}</td>
                  <td style={{padding:'11px 14px'}}><div style={{fontWeight:500}}>{s.parent}</div><div style={{fontSize:10,color:'#9CA3AF'}}>{s.phone}</div></td>
                  <td style={{padding:'11px 14px'}}><span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:600,background:'#F3F4F6',color:'#374151'}}>{s.cat}</span></td>
                  <td style={{padding:'11px 14px'}}><span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:700,background:bg,color:c}}>{label}</span></td>
                  <td style={{padding:'11px 14px'}}><span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:600,background:'#D1FAE5',color:'#065F46'}}>Active</span></td>
                  <td style={{padding:'11px 14px'}}>
                    <div style={{display:'flex',gap:6}}>
                      <button onClick={()=>setViewSt(s)} style={{padding:'5px 12px',border:'1px solid #1E1B4B',borderRadius:7,background:'#EDE9F8',color:'#1E1B4B',fontSize:11,fontWeight:600,cursor:'pointer'}}>View</button>
                      <button onClick={()=>toast.success(`ID Card for ${s.name}`)} style={{padding:'5px 10px',border:'1px solid #E5E7EB',borderRadius:7,background:'#fff',fontSize:11,cursor:'pointer'}}>ID</button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        <div style={{padding:'10px 14px',borderTop:'0.5px solid #E5E7EB',fontSize:11,color:'#6B7280',display:'flex',justifyContent:'space-between'}}>
          <span>Showing <strong>{filtered.length}</strong> of <strong>{students.length}</strong> students</span>
        </div>
      </div>

      {/* VIEW MODAL */}
      {viewSt&&(
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.5)',zIndex:400,display:'flex',alignItems:'center',justifyContent:'center',padding:20}}>
          <div style={{background:'#fff',borderRadius:18,width:500,maxHeight:'90vh',overflow:'auto'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center',position:'sticky',top:0,background:'#fff'}}>
              <div style={{fontWeight:700,fontSize:15}}>👨‍🎓 Student Profile</div>
              <button onClick={()=>setViewSt(null)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <div style={{padding:22}}>
              <div style={{display:'flex',alignItems:'center',gap:14,padding:16,background:'#EDE9F8',borderRadius:12,marginBottom:20}}>
                <div style={{width:52,height:52,borderRadius:14,background:'#1E1B4B',display:'flex',alignItems:'center',justifyContent:'center',fontSize:22,fontWeight:700,color:'#fff',flexShrink:0}}>{viewSt.name[0]}</div>
                <div>
                  <div style={{fontSize:17,fontWeight:800,color:'#111827'}}>{viewSt.name}</div>
                  <div style={{fontSize:12,color:'#6B7280',marginTop:2}}>Admission No: <strong>{viewSt.adm}</strong></div>
                  <div style={{display:'flex',gap:7,marginTop:6}}>
                    <span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#1E1B4B',color:'#fff'}}>{viewSt.cls} {viewSt.sec}</span>
                    <span style={{padding:'2px 8px',borderRadius:20,fontSize:10,...(()=>{const[bg,c]=FEE_BADGE[viewSt.fee]||FEE_BADGE.pending;return{background:bg,color:c};})()}}>{(FEE_BADGE[viewSt.fee]||FEE_BADGE.pending)[2]}</span>
                    <span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#D1FAE5',color:'#065F46'}}>Active</span>
                  </div>
                </div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12}}>
                {[['DOB',viewSt.dob||'—'],['Gender',viewSt.gender||'—'],['Blood',viewSt.blood||'—'],['Category',viewSt.cat],['Parent/Father',viewSt.parent],['Phone',viewSt.phone],['Address',viewSt.addr||'—'],['Status','Active']].map(([k,v])=>(
                  <div key={k} style={{padding:'10px 12px',background:'#F9FAFB',borderRadius:9}}>
                    <div style={{fontSize:10,color:'#9CA3AF',fontWeight:700,textTransform:'uppercase',marginBottom:4}}>{k}</div>
                    <div style={{fontSize:13,fontWeight:600,color:'#111827'}}>{v}</div>
                  </div>
                ))}
              </div>
              <div style={{display:'flex',gap:10,marginTop:18}}>
                <button onClick={()=>toast.success('Collect fee!')} style={{flex:1,padding:'10px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:600,cursor:'pointer'}}>💰 Collect Fee</button>
                <button onClick={()=>toast.success('ID card!')} style={{flex:1,padding:'10px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>📄 ID Card</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ADD STUDENT DRAWER */}
      {showAdd&&(
        <>
          <div onClick={closeAdd} style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:400}}/>
          <div style={{position:'fixed',top:0,right:0,bottom:0,width:480,maxWidth:'100vw',background:'#fff',zIndex:500,display:'flex',flexDirection:'column',boxShadow:'-8px 0 40px rgba(0,0,0,.15)'}}>
            {/* Drawer header */}
            <div style={{padding:'18px 22px',borderBottom:'1px solid #E5E7EB',display:'flex',alignItems:'center',justifyContent:'space-between',flexShrink:0}}>
              <div>
                <div style={{fontSize:16,fontWeight:800,color:'#111827'}}>🎓 New Student Admission</div>
                <div style={{fontSize:12,color:'#6B7280',marginTop:2}}>Step {step} of 3 — {STEPS[step-1]}</div>
              </div>
              <button onClick={closeAdd} style={{background:'#F3F4F6',border:'none',borderRadius:9,width:34,height:34,cursor:'pointer',fontSize:18,color:'#374151',display:'flex',alignItems:'center',justifyContent:'center'}}>✕</button>
            </div>

            {/* Step indicators */}
            <div style={{padding:'14px 22px',borderBottom:'1px solid #F3F4F6',display:'flex',flexShrink:0}}>
              {STEPS.map((label,i)=>{
                const n=i+1,done=step>n,active=step===n;
                return (
                  <div key={n} style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',gap:5,position:'relative'}}>
                    {i<2&&<div style={{position:'absolute',top:12,left:'55%',right:'-45%',height:2,background:done?'#1E1B4B':'#E5E7EB',zIndex:0}}/>}
                    <div style={{width:26,height:26,borderRadius:'50%',background:done||active?'#1E1B4B':'#F3F4F6',color:done||active?'#fff':'#9CA3AF',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:800,zIndex:1,border:`2px solid ${done||active?'#1E1B4B':'#E5E7EB'}`,position:'relative'}}>
                      {done?'✓':n}
                    </div>
                    <div style={{fontSize:10,fontWeight:700,color:active?'#1E1B4B':done?'#6B7280':'#9CA3AF',textAlign:'center'}}>{label}</div>
                  </div>
                );
              })}
            </div>

            {/* Form */}
            <form onSubmit={handleSubmit} style={{flex:1,overflowY:'auto',padding:'18px 22px'}}>
              {step===1&&(
                <>
                  <Sec title="Personal Details"/>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                    <Field label="First Name" required err={errors.firstName}><input value={form.firstName} onChange={e=>f('firstName',e.target.value)} placeholder="First name" style={inp(errors.firstName?{borderColor:'#DC2626'}:{})} autoFocus/></Field>
                    <Field label="Last Name"><input value={form.lastName} onChange={e=>f('lastName',e.target.value)} placeholder="Last name" style={inp()}/></Field>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:12}}>
                    <Field label="Date of Birth" required err={errors.dob}><input type="date" value={form.dob} onChange={e=>f('dob',e.target.value)} style={inp(errors.dob?{borderColor:'#DC2626'}:{})} max={new Date().toISOString().split('T')[0]}/></Field>
                    <Field label="Gender"><select value={form.gender} onChange={e=>f('gender',e.target.value)} style={inp()}><option value="male">Male</option><option value="female">Female</option><option value="other">Other</option></select></Field>
                    <Field label="Blood Group"><select value={form.blood} onChange={e=>f('blood',e.target.value)} style={inp()}><option value="">Select</option>{['A+','A-','B+','B-','O+','O-','AB+','AB-'].map(b=><option key={b}>{b}</option>)}</select></Field>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                    <Field label="Category"><select value={form.category} onChange={e=>f('category',e.target.value)} style={inp()}><option value="general">General</option><option value="obc">OBC</option><option value="sc">SC</option><option value="st">ST</option><option value="ews">EWS</option></select></Field>
                    <Field label="Religion"><input value={form.religion} onChange={e=>f('religion',e.target.value)} placeholder="e.g. Hindu" style={inp()}/></Field>
                  </div>
                  <Field label="Aadhaar Number"><input value={form.aadhaar} onChange={e=>f('aadhaar',e.target.value)} placeholder="12-digit (optional)" style={inp()} maxLength={12}/></Field>
                </>
              )}

              {step===2&&(
                <>
                  <Sec title="Parent / Guardian Details"/>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                    <Field label="Father's Name" required err={errors.fatherName}><input value={form.fatherName} onChange={e=>f('fatherName',e.target.value)} placeholder="Father's full name" style={inp(errors.fatherName?{borderColor:'#DC2626'}:{})} autoFocus/></Field>
                    <Field label="Mother's Name"><input value={form.motherName} onChange={e=>f('motherName',e.target.value)} placeholder="Mother's full name" style={inp()}/></Field>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                    <Field label="Primary Mobile" required err={errors.phone}><input value={form.phone} onChange={e=>f('phone',e.target.value)} placeholder="10-digit" style={inp(errors.phone?{borderColor:'#DC2626'}:{})} maxLength={10}/></Field>
                    <Field label="Alternate Mobile"><input value={form.altPhone} onChange={e=>f('altPhone',e.target.value)} placeholder="Optional" style={inp()} maxLength={10}/></Field>
                  </div>
                  <Field label="Email"><input type="email" value={form.email} onChange={e=>f('email',e.target.value)} placeholder="parent@email.com" style={{...inp(),marginBottom:12}}/></Field>
                  <Sec title="Residential Address"/>
                  <Field label="Full Address"><textarea value={form.address} onChange={e=>f('address',e.target.value)} placeholder="House no., Street, Locality…" rows={2} style={{...inp(),resize:'vertical',marginBottom:12}}/></Field>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12}}>
                    <Field label="City"><input value={form.city} onChange={e=>f('city',e.target.value)} placeholder="Lucknow" style={inp()}/></Field>
                    <Field label="State"><input value={form.state} onChange={e=>f('state',e.target.value)} style={inp()}/></Field>
                    <Field label="Pincode"><input value={form.pincode} onChange={e=>f('pincode',e.target.value)} placeholder="226001" style={inp()} maxLength={6}/></Field>
                  </div>
                </>
              )}

              {step===3&&(
                <>
                  <Sec title="Academic Placement"/>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:12}}>
                    <Field label="Class" required err={errors.class_}>
                      <select value={form.class_} onChange={e=>f('class_',e.target.value)} style={inp(errors.class_?{borderColor:'#DC2626'}:{})}>
                        <option value="">Select Class</option>{classes.map(c=><option key={c}>{c}</option>)}
                      </select>
                    </Field>
                    <Field label="Section"><select value={form.section} onChange={e=>f('section',e.target.value)} style={inp()}>{['A','B','C','D'].map(s=><option key={s}>{s}</option>)}</select></Field>
                    <Field label="Admission Date"><input type="date" value={form.admDate} onChange={e=>f('admDate',e.target.value)} style={inp()}/></Field>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:18}}>
                    <Field label="Previous School"><input value={form.prevSchool} onChange={e=>f('prevSchool',e.target.value)} placeholder="Previous school" style={inp()}/></Field>
                    <Field label="Prev Class / Marks%"><input value={form.prevMarks} onChange={e=>f('prevMarks',e.target.value)} placeholder="e.g. Class 5 · 82%" style={inp()}/></Field>
                  </div>
                  <div style={{padding:14,background:'#EDE9F8',borderRadius:12,marginBottom:14,fontSize:12}}>
                    <div style={{fontWeight:800,color:'#1E1B4B',marginBottom:8}}>📋 Summary</div>
                    <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:6,color:'#374151'}}>
                      {[['Name',`${form.firstName} ${form.lastName}`.trim()||'—'],['DOB',form.dob||'—'],['Class',form.class_?`${form.class_} - ${form.section}`:'—'],['Father',form.fatherName||'—'],['Phone',form.phone||'—'],['Category',form.category]].map(([k,v])=>(
                        <div key={k}><span style={{color:'#6B7280'}}>{k}: </span><strong>{v}</strong></div>
                      ))}
                    </div>
                  </div>
                  <div style={{padding:12,background:'#FEF3C7',borderRadius:10,fontSize:12,color:'#92400E',display:'flex',gap:8}}>
                    <span>💡</span><span>Admission number will be auto-generated on save.</span>
                  </div>
                </>
              )}

              {/* Footer */}
              <div style={{display:'flex',justifyContent:'space-between',marginTop:22,paddingTop:16,borderTop:'1px solid #F3F4F6',gap:10}}>
                <button type="button" onClick={closeAdd} style={{padding:'10px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <div style={{display:'flex',gap:10}}>
                  {step>1&&<button type="button" onClick={()=>setStep(step-1)} style={{padding:'10px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,fontWeight:600,cursor:'pointer'}}>← Back</button>}
                  <button type="submit" style={{padding:'10px 24px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:800,cursor:'pointer'}}>
                    {step<3?'Next Step →':'🎓 Admit Student'}
                  </button>
                </div>
              </div>
            </form>
          </div>
        </>
      )}
    </div>
  );
}
